sql:
SELECT COUNT(*) 
FROM questions 
WHERE difficulty_level = 'easy';

SELECT difficulty_level, COUNT(*) AS question_count
FROM questions
GROUP BY difficulty_level;

SELECT question_text, difficulty_level
FROM questions
WHERE difficulty_level = 'easy';

SELECT question_text, difficulty_level
FROM questions
ORDER BY difficulty_level ASC;

SELECT COUNT(*) AS total_correct_answers
FROM student_responses
WHERE is_correct = 1;

SELECT COUNT(question_id) AS total_questions
FROM quiz_questions
WHERE quiz_id = 0;

